insert into public.questions (
  question,
  correct_answer,
  options,
  category,
  difficulty,
  slug,
  explanation
)
values
  ('Wie sagt man "Fingerabdruck" auf Spanisch?', 'la huella dactilar', '["la huella dactilar","la mirada","la firma","el permiso"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-37', '"Huella dactilar" bedeutet Fingerabdruck und ist ein zentrales Identifikationsmerkmal in Ermittlungen.'),
  ('Wie sagt man "DNA" auf Spanisch?', 'el ADN', '["el ADN","la sangre","el hueso","el hígado"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-38', 'DNA heißt auf Spanisch "ADN" (ácido desoxirribonucleico). Der Begriff wird in Forensik und Medizin genutzt.'),
  ('Wie heißt "forensisches Labor" auf Spanisch?', 'el laboratorio forense', '["el laboratorio forense","el laboratorio químico","el despacho","la clínica"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-39', '"Laboratorio forense" ist das forensische Labor, in dem Spuren ausgewertet werden.'),
  ('Wie sagt man "Beweiskette" (Chain of custody) auf Spanisch?', 'la cadena de custodia', '["la cadena de custodia","la cadena de mando","la lista de guardia","la orden del juez"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-40', '"Cadena de custodia" ist die dokumentierte Beweiskette, die die Integrität der Beweise sichert.'),
  ('Wie heißt "Haftbefehl" auf Spanisch?', 'la orden de arresto', '["la orden de arresto","la orden de registro","la libertad condicional","el permiso"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-41', '"Orden de arresto" ist der Haftbefehl, der die Festnahme rechtlich erlaubt.'),
  ('Wie sagt man "Durchsuchungsbeschluss" auf Spanisch?', 'la orden de registro', '["la orden de registro","la orden de arresto","el permiso de conducir","la denuncia"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-42', '"Orden de registro" ist der Durchsuchungsbeschluss für Wohnung, Fahrzeug oder Objekt.'),
  ('Wie heißt "Hausdurchsuchung" auf Spanisch?', 'el allanamiento', '["el allanamiento","el interrogatorio","la vigilancia","la cita"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-43', '"Allanamiento" bedeutet Hausdurchsuchung bzw. polizeiliche Durchsuchung von Räumen.'),
  ('Wie sagt man "Verfolgungsjagd" auf Spanisch?', 'la persecución', '["la persecución","la patrulla","la revisión","la multa"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-44', '"Persecución" bezeichnet eine polizeiliche Verfolgungsjagd.'),
  ('Wie heißt "Geisel" auf Spanisch?', 'el/la rehén', '["el/la rehén","el/la testigo","el sospechoso","el juez"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-45', '"Rehén" bedeutet Geisel. Der Begriff bleibt gleich, nur der Artikel wechselt.'),
  ('Wie sagt man "Flucht" auf Spanisch?', 'la fuga', '["la fuga","la firma","la falta","la feria"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-46', '"Fuga" bedeutet Flucht, z. B. die Flucht eines Verdächtigen.'),
  ('Wie heißt "Aussage/Vernehmungsaussage" auf Spanisch?', 'la declaración', '["la declaración","la detención","la decisión","la dirección"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-47', '"Declaración" ist die Aussage, die eine Person bei der Polizei oder vor Gericht macht.'),
  ('Wie sagt man "Zeugenaussage" auf Spanisch?', 'el testimonio', '["el testimonio","el testigo","el testamento","el territorio"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-48', '"Testimonio" ist die Zeugenaussage; "testigo" ist die Person (Zeuge).'),
  ('Wie heißt "polizeilicher Bericht" auf Spanisch?', 'el atestado', '["el atestado","el contrato","el tratado","el mandato"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-49', '"Atestado" ist der polizeiliche Bericht oder Aktenvermerk zu einem Fall.'),
  ('Wie sagt man "Streife/Patrouille" auf Spanisch?', 'la patrulla', '["la patrulla","la parada","la parcela","la escuela"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-50', '"Patrulla" ist die Streife bzw. Patrouille im Einsatz.'),
  ('Wie heißt "Einsatz/Operation" auf Spanisch?', 'el operativo', '["el operativo","el protocolo","el objetivo","el permiso"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-51', '"Operativo" beschreibt einen Polizeieinsatz oder eine koordinierte Operation.'),
  ('Wie sagt man "Bodycam" auf Spanisch?', 'la cámara corporal', '["la cámara corporal","la cámara de fotos","la cámara de gas","la camilla"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-52', '"Cámara corporal" ist die am Körper getragene Kamera von Einsatzkräften.'),
  ('Wie heißt "Akte/Ermittlungsakte" auf Spanisch?', 'el expediente', '["el expediente","el experimento","el examen","el especialista"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-53', '"Expediente" ist die Akte bzw. der Fallordner in Ermittlungen.'),
  ('Wie sagt man "Absperrband" auf Spanisch?', 'la cinta policial', '["la cinta policial","la cinta métrica","la cinta adhesiva","la cinta musical"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-54', '"Cinta policial" ist das Absperrband, das einen Tatort sichert.'),
  ('Wie heißt "Gutachter/Forensiker" auf Spanisch?', 'el perito', '["el perito","el perrito","el permiso","el periodista"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-55', '"Perito" ist der Sachverständige oder forensische Gutachter in einem Fall.'),
  ('Wie sagt man "Notruf" auf Spanisch?', 'la llamada de emergencia', '["la llamada de emergencia","la llamada perdida","la llamada de trabajo","la llamada privada"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-56', '"Llamada de emergencia" ist ein Notruf, z. B. an die Polizei oder den Rettungsdienst.')
;

with translations as (
  select * from (values
    ('polizei-spanisch-2026-37', 'How do you say "fingerprint" in Spanish?', '["la huella dactilar","la mirada","la firma","el permiso"]'::jsonb, 'la huella dactilar', '"Huella dactilar" means fingerprint and is a key identifier in investigations.'),
    ('polizei-spanisch-2026-38', 'How do you say "DNA" in Spanish?', '["el ADN","la sangre","el hueso","el hígado"]'::jsonb, 'el ADN', 'DNA is "ADN" in Spanish (ácido desoxirribonucleico). The term is used in forensics.'),
    ('polizei-spanisch-2026-39', 'How do you say "forensic laboratory" in Spanish?', '["el laboratorio forense","el laboratorio químico","el despacho","la clínica"]'::jsonb, 'el laboratorio forense', '"Laboratorio forense" is the forensic lab where evidence is analyzed.'),
    ('polizei-spanisch-2026-40', 'How do you say "chain of custody" in Spanish?', '["la cadena de custodia","la cadena de mando","la lista de guardia","la orden del juez"]'::jsonb, 'la cadena de custodia', '"Cadena de custodia" is the documented chain of custody for evidence.'),
    ('polizei-spanisch-2026-41', 'How do you say "arrest warrant" in Spanish?', '["la orden de arresto","la orden de registro","la libertad condicional","el permiso"]'::jsonb, 'la orden de arresto', '"Orden de arresto" is the legal warrant that authorizes an arrest.'),
    ('polizei-spanisch-2026-42', 'How do you say "search warrant" in Spanish?', '["la orden de registro","la orden de arresto","el permiso de conducir","la denuncia"]'::jsonb, 'la orden de registro', '"Orden de registro" is a warrant that authorizes a search.'),
    ('polizei-spanisch-2026-43', 'How do you say "house search" in Spanish?', '["el allanamiento","el interrogatorio","la vigilancia","la cita"]'::jsonb, 'el allanamiento', '"Allanamiento" refers to a police search of premises.'),
    ('polizei-spanisch-2026-44', 'How do you say "police chase" in Spanish?', '["la persecución","la patrulla","la revisión","la multa"]'::jsonb, 'la persecución', '"Persecución" is a police pursuit or chase.'),
    ('polizei-spanisch-2026-45', 'How do you say "hostage" in Spanish?', '["el/la rehén","el/la testigo","el sospechoso","el juez"]'::jsonb, 'el/la rehén', '"Rehén" means hostage; the word stays the same and only the article changes.'),
    ('polizei-spanisch-2026-46', 'How do you say "escape" in Spanish?', '["la fuga","la firma","la falta","la feria"]'::jsonb, 'la fuga', '"Fuga" means escape, for example the escape of a suspect.'),
    ('polizei-spanisch-2026-47', 'How do you say "statement" in Spanish?', '["la declaración","la detención","la decisión","la dirección"]'::jsonb, 'la declaración', '"Declaración" is a statement given to police or in court.'),
    ('polizei-spanisch-2026-48', 'How do you say "testimony" in Spanish?', '["el testimonio","el testigo","el testamento","el territorio"]'::jsonb, 'el testimonio', '"Testimonio" is testimony; "testigo" is the witness.'),
    ('polizei-spanisch-2026-49', 'How do you say "police report" in Spanish?', '["el atestado","el contrato","el tratado","el mandato"]'::jsonb, 'el atestado', '"Atestado" is the formal police report or case record.'),
    ('polizei-spanisch-2026-50', 'How do you say "patrol" in Spanish?', '["la patrulla","la parada","la parcela","la escuela"]'::jsonb, 'la patrulla', '"Patrulla" refers to a patrol or patrol unit.'),
    ('polizei-spanisch-2026-51', 'How do you say "operation" in Spanish?', '["el operativo","el protocolo","el objetivo","el permiso"]'::jsonb, 'el operativo', '"Operativo" describes a police operation or coordinated deployment.'),
    ('polizei-spanisch-2026-52', 'How do you say "body camera" in Spanish?', '["la cámara corporal","la cámara de fotos","la cámara de gas","la camilla"]'::jsonb, 'la cámara corporal', '"Cámara corporal" is the body-worn camera used by officers.'),
    ('polizei-spanisch-2026-53', 'How do you say "case file" in Spanish?', '["el expediente","el experimento","el examen","el especialista"]'::jsonb, 'el expediente', '"Expediente" is the case file or investigation dossier.'),
    ('polizei-spanisch-2026-54', 'How do you say "police tape" in Spanish?', '["la cinta policial","la cinta métrica","la cinta adhesiva","la cinta musical"]'::jsonb, 'la cinta policial', '"Cinta policial" is police tape used to secure a crime scene.'),
    ('polizei-spanisch-2026-55', 'How do you say "forensic expert" in Spanish?', '["el perito","el perrito","el permiso","el periodista"]'::jsonb, 'el perito', '"Perito" is an expert witness or forensic specialist in a case.'),
    ('polizei-spanisch-2026-56', 'How do you say "emergency call" in Spanish?', '["la llamada de emergencia","la llamada perdida","la llamada de trabajo","la llamada privada"]'::jsonb, 'la llamada de emergencia', '"Llamada de emergencia" is an emergency call to police or rescue services.')
  ) as t(slug, question, options, correct_answer, explanation)
)
insert into public.question_translations (
  question_id,
  language,
  question,
  options,
  correct_answer,
  explanation
)
select q.id, 'en', t.question, t.options, t.correct_answer, t.explanation
from translations t
join public.questions q on q.slug = t.slug
on conflict (question_id, language) do update
  set question = excluded.question,
      options = excluded.options,
      correct_answer = excluded.correct_answer,
      explanation = excluded.explanation;
